import React, {useEffect, useState} from "react";
import type {IAccordionProps} from "@lmb/kitsconcerto-types";

import {
    Accordion,
    AccordionContent,
    AccordionContentText,
    AccordionHeader,
    AccordionIcon,
    AccordionItem,
    AccordionTitleText,
    AccordionTrigger,
    ChevronDownIcon,
    ChevronUpIcon,
    Divider
} from "@lmb/kitsconcertomobile";

import {Box, Heading} from "../"; // your existing KitsConcerto components

const CustomAccordion = ({
                             accordionTitle,
                             accordionItems,
                             isLoading,
                             allOpenedByDefault,
                             localProps,
                         }: IAccordionProps<any>) => {

    const [expanded, setExpanded] = useState<string[] | string>(
        localProps?.multiple ? ["0"] : "0"
    );

    // Apply "open all by default"
    useEffect(() => {
        if (allOpenedByDefault && accordionItems?.length) {
            const allValues = accordionItems.map((_, i) => `${i}`);
            setExpanded(localProps?.multiple ? allValues ?? ["0"] : allValues[0] ?? "0");
        }
    }, [allOpenedByDefault]);

    // Gluestack expects:
    // type="single" or "multiple"
    const type = localProps?.multiple ? "multiple" : "single";

    const handleChange = (val: string | string[]) => {
        setExpanded(val);

        // call item-specific onToggle if provided
        if (accordionItems) {
            if (Array.isArray(val)) {
                val.forEach((key) => {
                    const index = parseInt(key, 10);
                    accordionItems[index]?.onToggle?.(true);
                });
            } else {
                const index = parseInt(val, 10);
                accordionItems[index]?.onToggle?.(true);
            }
        }
    };

    return (
        <Box w="100%" borderRadius={8} overflow="hidden" className="bg-background-0">
            {!!accordionTitle && (
                <Heading as="h2" p={4} fontSize="lg" className="bg-background-100">
                    {accordionTitle}
                </Heading>
            )}

            {isLoading ? (
                <Box p={4}>
                    {/* Replace with RN skeleton later */}
                </Box>
            ) : (
                <Accordion
                    {...localProps}
                    value={expanded}
                    onValueChange={handleChange}
                    type={type}
                    className="w-full"
                >
                    {accordionItems?.map(({button, panel}, i) => (
                        <React.Fragment key={i}>
                            <AccordionItem value={`${i}`}>
                                <AccordionHeader>
                                    <AccordionTrigger>
                                        {({isExpanded}:{isExpanded:boolean}) => (
                                            <>
                                                <AccordionTitleText>{button}</AccordionTitleText>
                                                <AccordionIcon
                                                    as={isExpanded ? ChevronUpIcon : ChevronDownIcon}
                                                    className="ml-3"
                                                />
                                            </>
                                        )}
                                    </AccordionTrigger>
                                </AccordionHeader>

                                <AccordionContent>
                                    <AccordionContentText>
                                        {panel}
                                    </AccordionContentText>
                                </AccordionContent>
                            </AccordionItem>

                            {i !== accordionItems.length - 1 && <Divider/>}
                        </React.Fragment>
                    ))}
                </Accordion>
            )}
        </Box>
    );
};

export default CustomAccordion;
